const input = $('Execute Workflow Trigger').item.json;
const agent = $('Buscar agente').item.json;
const channel = $('Buscar canal').item.json;

if (!agent?.id) throw new Error('Agente nao encontrado: ' + input.agentId);
if (!channel?.channel_id) throw new Error('Canal nao encontrado: ' + input.channelId);

const parse = (v) => (typeof v === 'string' ? JSON.parse(v) : v);

return [{
  json: {
    agentId: agent.id,
    agentName: agent.name,
    baseInstructions: agent.base_instructions,
    basePersonality: parse(agent.base_personality),
    channel: {
      channelId: channel.channel_id,
      enabled: channel.enabled,
      useSharedPersonality: channel.use_shared_personality,
      useSharedKnowledgeBase: channel.use_shared_knowledge_base,
      personality: channel.personality ? parse(channel.personality) : null,
      instructions: channel.instructions || '',
    },
  },
}];
